import React, { useState } from 'react';

const InputArea = ({ currentStep, onSendMessage, isTyping }) => {
  const [inputValue, setInputValue] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (inputValue.trim() && !isTyping) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  if (!currentStep || isTyping) return <div className="h-16" />; // Keep space for typing indicator

  return (
    <div className="p-4 border-t bg-white">
      {currentStep.type === 'text' || currentStep.type === 'voice_text' ? (
        <form onSubmit={handleSubmit} className="flex gap-2">
          <input
            type="text"
            className="flex-1 p-3 border rounded-full focus:outline-none focus:ring-2 focus:ring-emerald-500"
            placeholder="Type your message..."
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
          />
          <button 
            type="submit"
            className="bg-emerald-600 text-white px-6 py-2 rounded-full font-medium"
          >
            Send
          </button>
        </form>
      ) : currentStep.type === 'choice' ? (
        <div className="flex flex-wrap gap-2 justify-center">
          {currentStep.options.map((option) => (
            <button
              key={option}
              onClick={() => onSendMessage(option)}
              className="px-6 py-2 border-2 border-emerald-600 text-emerald-700 rounded-full hover:bg-emerald-50 font-medium transition-colors"
            >
              {option}
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
};

export default InputArea;
